// =======================
// IMAGE INDEX TRACKER
// =======================
const imageIndex = {};

// =======================
// DISPLAY HOSTELS
// =======================
function displayHostels(list) {
    const hostelList = document.getElementById("hostelList");
    hostelList.innerHTML = "";

    if (list.length === 0) {
        hostelList.innerHTML = "";
        return;
    }

    list.forEach((hostel, index) => {
        imageIndex[index] = 0;

        hostelList.innerHTML += `
            <div class="hostel-card">
                <div class="slider">
                    <img id="img-${index}" src="${hostel.images[0]}" alt="Hostel Image">
                    <button class="prev" onclick="changeImage(${index}, -1)">❮</button>
                    <button class="next" onclick="changeImage(${index}, 1)">❯</button>
                </div>

                <h3>${hostel.name}</h3>
                <p><strong>City:</strong> ${hostel.city}</p>
                <p><strong>Area:</strong> ${hostel.area}</p>
                <p><strong>Rent:</strong> ₹${hostel.price}/month</p>
          <button class="more-btn" onclick="toggleInfo('info1')">More Info</button>

<div class="more-info" id="info1">
<ul>
  <li><p><b>Rooms:</b> 1,2,3 & 4 Sharing</p></li>
<li>  <p><b>Amenities:</b> <ol><li>WiFi</li><li>24/7 CCTV</li><li>Power Backup</li><li>Hot Water</li></ol>
  <li><p><b>Meals:</b> Breakfast & Dinner</p></li>
  <li><p><b>Laundry:</b> Available</p></li>
  <li><p><b>Contact:</b> 9876543210</p></li>
  </ul>
</div> 
<button class="more-btn" onclick="toggleInfo('info2')">Location</button>

<div class="more-info" id="info2">
<b>Location:</b>
<img src="https://www.google.com/maps/vt/data=4aoFCb7ML-IHaBkCijjJTOjT9l49QNO4C2D14ooKHRoh3QOrOODSi4SX2A_V5IEHdse65s1IbqGN1H7HcQsn8GOjIkFDpWGzXJ6_aY2os90ZddM39yF1dewLG1BB0QLENZquQMciaEkL0UVYbjvRu7IjupeZZ__h6H3x1_PFSq_4otf_nyHGF65codVATvarGIaElSzAL6eqPOLaFBWqTdAI4F7WV07P6u5uOnOq6glOOKU6i70EEbJwl0jHDB7DFZfJUT9C2EXBioi5aV2DWq9f_lo" height=300 width=500>
</div>

            
        `;
    });

}

// =======================
// CHANGE IMAGE (SLIDER LOGIC)
// =======================
function changeImage(cardIndex, direction) {
    const images = hostels[cardIndex].images;

    imageIndex[cardIndex] += direction;

    if (imageIndex[cardIndex] < 0) {
        imageIndex[cardIndex] = images.length - 1;
    }

    if (imageIndex[cardIndex] >= images.length) {
        imageIndex[cardIndex] = 0;
    }

    document.getElementById(`img-${cardIndex}`).src =
        images[imageIndex[cardIndex]];
}

// =======================
// SEARCH HOSTELS BY CITY
// =======================
function searchHostels() {
    const searchValue = document
        .getElementById("searchInput")
        .value
        .toLowerCase();

    const message = document.getElementById("noResultMessage");

    const filteredHostels = hostels.filter(hostel =>
        hostel.city.toLowerCase().includes(searchValue)
    );

    if (filteredHostels.length === 0) {
        message.style.display = "block";
    } else {
        message.style.display = "none";
    }

    displayHostels(filteredHostels);
}

// =======================
// ENTER KEY SEARCH
// =======================
function handleEnter(event) {
    if (event.key === "Enter") {
        searchHostels();
    }
}

// =======================
// INITIAL LOAD
// =======================
function toggleMoreInfo(button) {
  const info = button.nextElementSibling;

  if (info.style.display === "block") {
    info.style.display = "none";
    button.innerHTML = "More Info ⌄";
  } else {
    info.style.display = "block";
    button.innerHTML = "More Info ⌃";
  }
}

